using UnityEngine;

/// <summary>
/// Argola/ponto de fixação para a língua (P5 — TonguePullAbility,
/// "canPullToSelf: língua / puxar argolas"): quando a língua acerta numa
/// argola, é o PLAYER que é puxado até ela (travessias de precipícios, etc).
/// Requer um Collider2D (pode ser trigger).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class TongueAnchor : MonoBehaviour
{
    private void OnDrawGizmos()
    {
        Gizmos.color = new Color(1f, 0.5f, 0.8f, 0.8f);
        Gizmos.DrawWireSphere(transform.position, 0.25f);
    }
}
